class Solution {
public:
    int majorityElement(vector<int>& nums) {
        int majority = 0;
        int count = 0;

        for (int i: nums){
            if (count == 0){
                majority = i;
            }

            if (i == majority)
                count++;
            else
                count--;

        }

        return majority;

    }
};
